record.field:
for rec in records:
    values = {}

    if not rec.x_intake_reference:
        values['x_intake_reference'] = env['ir.sequence'].next_by_code('x_hr.pool') or 'MCEP-HR-F1-0001'

    if not rec.x_name:
        name_parts = [part for part in [rec.x_first_name_ar, rec.x_surname_ar] if part]
        if name_parts:
            values['x_name'] = ' '.join(name_parts).strip()

    if values:
        rec.write(values)
